mapper.select:
SELECT CERT_IMAGE_URL
FROM MEMBER_MISSION_TBL
WHERE MEMBER_ID = #{memberId}
  AND MISSION_NO = #{missionNo}
  AND COMPLETED_YMD = TRUNC(SYSDATE)

mapper.update:
UPDATE MEMBER_POINT_TBL
SET TOTAL_POINT = TOTAL_POINT + 5
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER_POINT_TBL
SET TOTAL_POINT = TOTAL_POINT + 10
WHERE MEMBER_ID = #{memberId}

mapper.select:
SELECT COUNT(*)
FROM MEMBER_MISSION_TBL
WHERE MEMBER_ID = #{memberId}
  AND MISSION_NO = #{missionNo}
  AND COMPLETED_YMD = TRUNC(SYSDATE)

mapper.update:
UPDATE MEMBER_MISSION_TBL
SET CERT_IMAGE_URL = #{certImageUrl},
    COMPLETED_YMD = TRUNC(SYSDATE)
WHERE MEMBER_ID = #{memberId}
  AND MISSION_NO = #{missionNo}
  AND COMPLETED_YMD IS NULL

UPDATE MEMBER_POINT_TBL
SET TOTAL_POINT = TOTAL_POINT + 20
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER_POINT_TBL
SET TOTAL_POINT = TOTAL_POINT + #{rewardPoint}
WHERE MEMBER_ID = #{memberId}
